codeunit 50100 A1
{
    procedure A(var Cust: Record Customer)
    begin
        Cust.SetRange("No.", Helper());
    end;

    procedure Helper(): Code[20]
    begin
        exit('x');
    end;
}

codeunit 50100 A2
{
    procedure Gap(var Cust: Record Customer; flag: Boolean)
    begin
        Cust.FindSet();
        if flag then
            exit;
        Cust.Modify();
    end;
}

codeunit 50100 B1
{
    procedure Branches(var Cust: Record Customer)
    begin
        if Cust.IsEmpty() then
            Cust.Init()
        else
            Cust.Modify();
    end;
}

codeunit 50100 B2
{
    procedure Implicit(var Cust: Record Customer; flag: Boolean)
    begin
        if flag then
            Cust.Modify();
    end;
}

codeunit 50100 B3
{
    procedure CaseLoop(var Cust: Record Customer; i: Integer)
    begin
        case i of
            1:
                Cust.Insert();
            2:
                exit;
        end;
        while i < 10 do
            Cust.Modify();
    end;
}

codeunit 50100 B4
{
    procedure RepeatLoop(var Cust: Record Customer)
    begin
        repeat
            Cust.Modify();
        until Cust.Next() = 0;
    end;
}

codeunit 50100 C1
{
    procedure ExitArm(var Cust: Record Customer; flag: Boolean)
    begin
        if flag then begin
            Cust.Modify();
            exit;
        end;
    end;
}

codeunit 50100 C2
{
    procedure ErrArm(var Cust: Record Customer; bad: Boolean)
    begin
        if bad then begin
            Cust.Modify();
            Error('boom');
        end;
        Cust.Insert();
    end;
}

codeunit 50100 C3
{
    procedure BothExit(var Cust: Record Customer; flag: Boolean)
    begin
        if flag then
            exit
        else
            exit;
        Cust.Modify();
    end;
}

codeunit 50100 C4
{
    procedure BareErr(var Cust: Record Customer)
    begin
        Cust.FindSet();
        Error('always');
    end;
}

codeunit 50100 D1
{
    procedure DomGuard(var Cust: Record Customer; flag: Boolean)
    begin
        Cust.FindSet();
        if flag then
            exit;
        Cust.Modify();
    end;
}

codeunit 50100 D2
{
    procedure NestedDom(var Cust: Record Customer; i: Integer; flag: Boolean)
    begin
        Cust.FindSet();
        if flag then
            Cust.Modify();
        while i < 10 do
            Cust.Delete();
        case i of
            1:
                Cust.Insert();
        end;
    end;
}

codeunit 50100 D3
{
    procedure OtherDom(var Cust: Record Customer)
    var
        n: Integer;
    begin
        n := Compute();
    end;

    procedure Compute(): Integer
    begin
        exit(1);
    end;
}

codeunit 50100 E
{
    [TryFunction]
    procedure TryIt(var Cust: Record Customer)
    begin
        Cust.FindSet();
        if Cust.IsEmpty() then
            Cust.Modify();
        Commit();
    end;
}

codeunit 50100 F
{
    procedure Empty()
    begin
    end;
}

codeunit 50100 G
{
    procedure ErrGuard(var Cust: Record Customer)
    begin
        Cust.FindSet();
        if Cust.IsEmpty() then
            Error('empty');
    end;
}
